#include <stdio.h>
#include <stdlib.h>

#define N 100005

int T, n, q, a[N], pre[N], ans[N];

int read() {
    int x = 0, f = 1;
    char c = getchar();
    while (c < '0' || c > '9') {
        if (c == '-')
            f = -1;
        c = getchar();
    }
    while (c >= '0' && c <= '9') {
        x = x * 10 + c - '0';
        c = getchar();
    }
    return x * f;
}

void write(int x) {
    if (x < 0) {
        putchar('-');
        x = -x;
    }
    if (x > 9)
        write(x / 10);
    putchar(x % 10 + '0');
}

int main() {
    T = read();
    while (T--) {
        n = read();
        for (int i = 1; i <= n; i++)
            a[i] = read();
        q = read();
        for (int i = 1; i <= n; i++)
            pre[i] = pre[i - 1] & a[i];
        while (q--) {
            int l = read(), r = read();
            if (pre[r] & pre[l - 1])
                write('E');
            else
                write('O');
            putchar('\n');
        }
    }
    return 0;
}

