code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n + 1];
            int[] pre = new int[n + 1];
            for (int i = 1; i <= n; i++)
                a[i] = sc.nextInt();
            int q = sc.nextInt();
            for (int i = 1; i <= n; i++)
                pre[i] = pre[i - 1] & a[i];
            while (q-- > 0) {
                int l = sc.nextInt(), r = sc.nextInt();
                if (pre[r] & pre[l - 1])
                    System.out.println("EVEN");
                else
                    System.out.println("ODD");
            }
        }
    }
}

